use std::os::raw::{c_char};
use std::ffi::CStr;

#[no_mangle]
pub extern "C" fn greet(name: *const c_char) {
    let name_str = unsafe { CStr::from_ptr(name).to_str() }
        .unwrap_or("invalid utf-8") // Proper error handling
        .to_string();
    println!("Hello, {}!", name_str);
}
